Code.Terraform:
```hcl
# Terraform: WAF Classic のグローバルルールグループに少なくとも 1 つのルールがあることを確認する
resource "aws_waf_rule_group" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "examplemetric"

  activated_rule {
    priority = 1                      # 重要: グループにルールを追加します（空ではなくなります）
    rule_id  = "<example_resource_id>" # 重要: 追加する既存ルールのID
    action {
      type = "BLOCK"                 # 重要: ルールを有効化する際に必要な操作
    }
  }
}
```
